 1	import * as React from 'react';
 2	import cn from 'classnames';
 3	import * as _ from 'lodash-es';
 4	import { CopyToClipboard as CTC } from 'react-copy-to-clipboard';
 5	import { Button, Tooltip } from '@patternfly/react-core';
 6	import { CopyIcon } from '@patternfly/react-icons';
 7	import { useCustomTranslation } from '../useCustomTranslationHook';
 8	import '../style.scss';
 9	
10	type CopyToClipboardWrapperProps = {
11	  visibleValue: React.ReactNode;
12	  iconOnly?: boolean;
13	};
14	
15	const CopyToClipboardWrapper: React.FC<CopyToClipboardWrapperProps> = ({
16	  visibleValue,
17	  iconOnly,
18	  children,
19	}) => {
20	  return iconOnly ? (
21	    <>{children}</>
22	  ) : (
23	    <div className="odf-copy-to-clipboard">
24	      <pre
25	        className="odf-pre-wrap odf-copy-to-clipboard__text odf-copy-to-clipboard__pre"
26	        data-test="copy-to-clipboard"
27	      >
28	        {visibleValue}
29	      </pre>
30	      {children}
31	    </div>
32	  );
33	};
34	
35	export const CopyToClipboard: React.FC<CopyToClipboardProps> = React.memo(
36	  (props) => {
37	    const [copied, setCopied] = React.useState(false);
38	
39	    const { t } = useCustomTranslation();
40	    const tooltipText = copied ? t('Copied') : t('Copy to clipboard');
41	    const tooltipContent = [
42	      <span className="co-nowrap" key="nowrap">
43	        {tooltipText}
44	      </span>,
45	    ];
46	
47	    // Default to value if no visible value was specified.
48	    const visibleValue = _.isNil(props.visibleValue)
49	      ? props.value
50	      : props.visibleValue;
51	
52	    return (
53	      <CopyToClipboardWrapper
54	        visibleValue={visibleValue}
55	        iconOnly={props.iconOnly}
56	      >
57	        <Tooltip
58	          content={tooltipContent}
59	          trigger="click mouseenter focus"
60	          exitDelay={1250}
61	        >
62	          <CTC text={props.value} onCopy={() => setCopied(true)}>
63	            <Button
64	              variant="plain"
65	              onMouseEnter={() => setCopied(false)}
66	              className={cn(
67	                'odf-copy-to-clipboard__btn',
68	                'pf-v6-c-clipboard-copy__group-copy',
69	                { 'odf-copy-to-clipboard__btn--icon-only': props.iconOnly }
70	              )}
71	              type="button"
72	              data-test="copy-to-clipboard-btn"
73	            >
74	              <CopyIcon />
75	              <span className="sr-only">{t('Copy to clipboard')}</span>
76	            </Button>
77	          </CTC>
78	        </Tooltip>
79	      </CopyToClipboardWrapper>
80	    );
81	  }
82	);
83	
84	export type CopyToClipboardProps = {
85	  value: string;
86	  visibleValue?: React.ReactNode;
87	  iconOnly?: boolean;
88	};
89	
90	CopyToClipboard.displayName = 'CopyToClipboard';

